import{_ as t,o as a,c as i,a2 as r}from"./chunks/framework.Crpw6aS5.js";const p=JSON.parse('{"title":"Archive Sharing","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/sharing.md","filePath":"en/guide/sharing.md"}'),n={name:"en/guide/sharing.md"};function o(l,e,s,d,h,c){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="archive-sharing" tabindex="-1">Archive Sharing <a class="header-anchor" href="#archive-sharing" aria-label="Permalink to &quot;Archive Sharing&quot;">​</a></h1><p>The sharing feature lets you generate <strong>temporary links</strong> to share an archived email with someone who doesn&#39;t have an account on the application.</p><h2 id="create-a-share-link" tabindex="-1">Create a Share Link <a class="header-anchor" href="#create-a-share-link" aria-label="Permalink to &quot;Create a Share Link&quot;">​</a></h2><p>From the <strong>Sharing</strong> page (Tools menu):</p><ol><li>Click on an archived email</li><li>Choose the <strong>validity period</strong> (1 hour to 30 days)</li><li>Optionally, set a <strong>maximum number of accesses</strong></li><li>The link is generated and can be copied to the clipboard</li></ol><h2 id="share-parameters" tabindex="-1">Share Parameters <a class="header-anchor" href="#share-parameters" aria-label="Permalink to &quot;Share Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th style="text-align:center;">Default Value</th></tr></thead><tbody><tr><td><strong>Duration</strong></td><td>How long the link is valid</td><td style="text-align:center;">24 hours</td></tr><tr><td><strong>Max accesses</strong></td><td>Number of times the link can be used</td><td style="text-align:center;">Unlimited</td></tr></tbody></table><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><ul><li>Links use a <strong>64-character cryptographic token</strong> (256 bits of entropy)</li><li>Links expire automatically — cleanup runs every hour</li><li><strong>Encrypted</strong> emails cannot be shared</li><li>Content is served in a <strong>sandboxed iframe</strong> (no script execution)</li><li>Each access is tracked</li></ul><h2 id="link-management" tabindex="-1">Link Management <a class="header-anchor" href="#link-management" aria-label="Permalink to &quot;Link Management&quot;">​</a></h2><p>The sharing page displays all your active links with:</p><ul><li>The subject and sender of the shared email</li><li>The expiration date</li><li>The access count</li></ul><p>You can <strong>revoke</strong> a link at any time by clicking the delete icon.</p><h2 id="public-view" tabindex="-1">Public View <a class="header-anchor" href="#public-view" aria-label="Permalink to &quot;Public View&quot;">​</a></h2><p>People who receive the link access a clean public page displaying:</p><ul><li>The subject, sender, and date of the email</li><li>The HTML or text content of the email</li><li>A &quot;Mail shared via temporary link&quot; badge</li></ul><p>No authentication is required to view a valid link.</p><h2 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th style="text-align:center;">Auth</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/api/shares</code></td><td style="text-align:center;">Yes</td><td>List my shares</td></tr><tr><td><code>POST</code></td><td><code>/api/shares</code></td><td style="text-align:center;">Yes</td><td>Create a link</td></tr><tr><td><code>DELETE</code></td><td><code>/api/shares/:id</code></td><td style="text-align:center;">Yes</td><td>Revoke a link</td></tr><tr><td><code>GET</code></td><td><code>/api/shares/public/:token</code></td><td style="text-align:center;">No</td><td>Access the shared email</td></tr></tbody></table>',19)])])}const g=t(n,[["render",o]]);export{p as __pageData,g as default};
